#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <regex>
using namespace std;

vector<int> solution(int n, vector<vector<int>>& edges, string labels) {
    // Build adjacency list
    vector<vector<int>> adj(n);
    for (auto& edge : edges) {
        adj[edge[0]].push_back(edge[1]);
        adj[edge[1]].push_back(edge[0]);
    }

    vector<int> result(n);

    function<int(int, int, char)> dfs = [&](int node, int parent, char targetLabel) {
        int count = (labels[node] == targetLabel) ? 1 : 0;
        for (int neighbor : adj[node]) {
            if (neighbor != parent) {
                count += dfs(neighbor, node, targetLabel);
            }
        }
        return count;
    };

    for (int i = 0; i < n; i++) {
        result[i] = dfs(i, -1, labels[i]);
    }

    return result;
}

int main() {
    int n;
    cin >> n;
    cin.ignore();

    string edgesLine;
    getline(cin, edgesLine);

    string labels;
    getline(cin, labels);

    // Parse edges using regex for more robust parsing
    vector<vector<int>> edges;
    regex edge_regex(R"(\[(\d+),(\d+)\])");
    sregex_iterator iter(edgesLine.begin(), edgesLine.end(), edge_regex);
    sregex_iterator end;

    for (; iter != end; ++iter) {
        smatch match = *iter;
        int u = stoi(match[1].str());
        int v = stoi(match[2].str());
        edges.push_back({u, v});
    }

    vector<int> result = solution(n, edges, labels);
    cout << "[";
    for (int i = 0; i < result.size(); i++) {
        cout << result[i];
        if (i < result.size() - 1) cout << ",";
    }
    cout << "]" << endl;
    return 0;
}
